  1→/**
  2→ * Context loader: effect boundary for loading graph context needed by LLM reasoning.
  3→ *
  4→ * Encapsulates all SurrealDB queries needed to assemble the reasoning context.
  5→ * Returns plain data objects consumed by both deterministic and LLM pipelines.
  6→ */
  7→
  8→import { RecordId, type Surreal } from "surrealdb";
  9→
 10→// ---------------------------------------------------------------------------
 11→// Types
 12→// ---------------------------------------------------------------------------
 13→
 14→export type RelatedDecision = {
 15→  id: string;
 16→  table_id: string;
 17→  summary: string;
 18→  status: string;
 19→  rationale?: string;
 20→};
 21→
 22→export type EntityContext = {
 23→  entityTable: string;
 24→  entityId: string;
 25→  entityTitle: string;
 26→  entityDescription?: string;
 27→  entityStatus?: string;
 28→  relatedDecisions: RelatedDecision[];
 29→  validEntityIds: Set<string>;
 30→};
 31→
 32→// ---------------------------------------------------------------------------
 33→// Load related decisions for an entity's project (max 20, by recency)
 34→// ---------------------------------------------------------------------------
 35→
 36→export async function loadRelatedDecisions(
 37→  surreal: Surreal,
 38→  workspaceRecord: RecordId<"workspace", string>,
 39→  projectRecord?: RecordId<"project", string>,
 40→): Promise<RelatedDecision[]> {
 41→  if (!projectRecord) return [];
 42→
 43→  const [rows] = await surreal.query<[Array<{
 44→    id: RecordId<"decision">;
 45→    summary: string;
 46→    status: string;
 47→    rationale?: string;
 48→    updated_at: string | Date;
 49→  }>]>(
 50→    `SELECT id, summary, status, rationale, updated_at FROM decision
 51→     WHERE workspace = $ws
 52→       AND status IN ["confirmed", "provisional"]
 53→       AND ->belongs_to->project CONTAINS $project
 54→     ORDER BY updated_at DESC
 55→     LIMIT 20;`,
 56→    { ws: workspaceRecord, project: projectRecord },
 57→  );
 58→
 59→  return (rows ?? []).map((row) => ({
 60→    id: row.id.id as string,
 61→    table_id: `decision:${row.id.id as string}`,
 62→    summary: row.summary,
 63→    status: row.status,
 64→    rationale: row.rationale,
 65→  }));
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Resolve the project for an entity via belongs_to edge
 70→// ---------------------------------------------------------------------------
 71→
 72→export async function resolveEntityProject(
 73→  surreal: Surreal,
 74→  entityTable: string,
 75→  entityId: string,
 76→): Promise<RecordId<"project", string> | undefined> {
 77→  const entityRecord = new RecordId(entityTable, entityId);
 78→
 79→  const [rows] = await surreal.query<[Array<{
 80→    project: RecordId<"project">[];
 81→  }>]>(
 82→    `SELECT ->belongs_to->project AS project FROM $entity;`,
 83→    { entity: entityRecord },
 84→  );
 85→
 86→  const projects = rows?.[0]?.project;
 87→  if (!projects || projects.length === 0) return undefined;
 88→
 89→  return projects[0] as RecordId<"project", string>;
 90→}
 91→
 92→// ---------------------------------------------------------------------------
 93→// Load entity body from DB when not provided by caller
 94→// ---------------------------------------------------------------------------
 95→
 96→async function loadEntityBody(
 97→  surreal: Surreal,
 98→  entityTable: string,
 99→  entityId: string,
100→): Promise<Record<string, unknown> | undefined> {
101→  const entityRecord = new RecordId(entityTable, entityId);
102→
103→  const [rows] = await surreal.query<[Array<Record<string, unknown>>]>(
104→    `SELECT title, summary, description, status FROM $entity;`,
105→    { entity: entityRecord },
106→  );
107→
108→  return rows?.[0];
109→}
110→
111→// ---------------------------------------------------------------------------
112→// Build complete entity context for LLM reasoning
113→// ---------------------------------------------------------------------------
114→
115→export async function buildEntityContext(
116→  surreal: Surreal,
117→  workspaceRecord: RecordId<"workspace", string>,
118→  entityTable: string,
119→  entityId: string,
120→  entityBody?: Record<string, unknown>,
121→): Promise<EntityContext> {
122→  // Load entity from DB when body not provided by caller
123→  const body = entityBody ?? await loadEntityBody(surreal, entityTable, entityId);
124→  const entityTitle = (body?.title as string) ?? (body?.summary as string) ?? "Unknown";
125→  const entityDescription = body?.description as string | undefined;
126→  const entityStatus = body?.status as string | undefined;
127→
128→  // Resolve project and load related decisions
129→  const projectRecord = await resolveEntityProject(surreal, entityTable, entityId);
130→  const relatedDecisions = await loadRelatedDecisions(surreal, workspaceRecord, projectRecord);
131→
132→  // Build valid entity ID set for evidence validation
133→  const validEntityIds = new Set<string>();
134→  validEntityIds.add(`${entityTable}:${entityId}`);
135→  for (const d of relatedDecisions) {
136→    validEntityIds.add(d.table_id);
137→  }
138→  if (projectRecord) {
139→    validEntityIds.add(`project:${projectRecord.id as string}`);
140→  }
141→
142→  return {
143→    entityTable,
144→    entityId,
145→    entityTitle,
146→    entityDescription,
147→    entityStatus,
148→    relatedDecisions,
149→    validEntityIds,
150→  };
151→}
