 10→
 11→// ---------------------------------------------------------------------------
 12→// Types
 13→// ---------------------------------------------------------------------------
 14→
 15→export type CiStatus = "success" | "failure" | "pending" | "unknown";
 16→
 17→export type ExternalSignal = {
 18→  sha: string;
 19→  repository: string;
 20→  ciStatus: CiStatus;
 21→  source: string;
 22→};
 23→
 24→export type GatherSignalsResult = {
 25→  signals: ExternalSignal[];
 26→  hasCommits: boolean;
 27→};
 28→
 29→type CommitRecord = {
 30→  id: RecordId<"git_commit", string>;
 31→  sha: string;
 32→  repository?: string;
 33→};
 34→
 35→// ---------------------------------------------------------------------------
 36→// Gather linked commits for a task
 37→// ---------------------------------------------------------------------------
 38→
 39→export async function gatherLinkedCommits(
 40→  surreal: Surreal,
 41→  taskId: string,
 42→): Promise<CommitRecord[]> {
 43→  const taskRecord = new RecordId("task", taskId);
 44→
 45→  // Check source_commit field on the task
 46→  const [taskRows] = await surreal.query<
 47→    [Array<{ source_commit?: RecordId<"git_commit", string> }>]
 48→  >(
 49→    `SELECT source_commit FROM $task;`,
 50→    { task: taskRecord },
 51→  );
 52→
 53→  const sourceCommit = taskRows?.[0]?.source_commit;
 54→  if (!sourceCommit) return [];
 55→
 56→  // Fetch the commit record
 57→  const [commitRows] = await surreal.query<[CommitRecord[]]>(
 58→    `SELECT id, sha, repository FROM $commit;`,
 59→    { commit: sourceCommit },
 60→  );
 61→
 62→  return commitRows ?? [];
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Check CI status for a commit (GitHub API)
 67→// ---------------------------------------------------------------------------
 68→
 69→export async function checkCiStatus(
 70→  commit: CommitRecord,
 71→): Promise<ExternalSignal> {
 72→  const sha = commit.sha;
 73→  const repository = commit.repository ?? "";
 74→
 75→  if (!repository) {
 76→    return { sha, repository, ciStatus: "unknown", source: "none" };
 77→  }
 78→
 79→  // Attempt GitHub commit status API (configurable base URL for testing)
 80→  const githubBaseUrl = process.env.GITHUB_API_URL ?? "https://api.github.com";
 81→  const githubApiUrl = `${githubBaseUrl}/repos/${repository}/commits/${sha}/status`;
 82→
 83→  try {
 84→    const response = await fetch(githubApiUrl, {
 85→      headers: {
 86→        Accept: "application/vnd.github.v3+json",
 87→        ...(process.env.GITHUB_TOKEN
 88→          ? { Authorization: `Bearer ${process.env.GITHUB_TOKEN}` }
 89→          : {}),
 90→      },
 91→      signal: AbortSignal.timeout(10_000),
 92→    });
 93→
 94→    if (!response.ok) {
 95→      logInfo("observer.ci_check.http_error", "GitHub API returned non-OK", {
 96→        status: response.status,
 97→        sha,
 98→        repository,
 99→      });
100→      return { sha, repository, ciStatus: "unknown", source: "github" };
101→    }
102→
103→    const data = (await response.json()) as { state?: string };
104→    const ciStatus = mapGitHubState(data.state);
105→
106→    return { sha, repository, ciStatus, source: "github" };
107→  } catch (error) {
108→    logError("observer.ci_check.failed", "Failed to check CI status", error);
109→    return { sha, repository, ciStatus: "unknown", source: "github" };
110→  }
111→}
112→
113→function mapGitHubState(state?: string): CiStatus {
114→  switch (state) {
115→    case "success":
116→      return "success";
117→    case "failure":
118→    case "error":
119→      return "failure";
120→    case "pending":
121→      return "pending";
122→    default:
123→      return "unknown";
124→  }
125→}
126→
127→// ---------------------------------------------------------------------------
128→// Gather all external signals for a task
129→// ---------------------------------------------------------------------------
130→
131→export async function gatherTaskSignals(
132→  surreal: Surreal,
133→  taskId: string,
134→): Promise<GatherSignalsResult> {
135→  const commits = await gatherLinkedCommits(surreal, taskId);
136→
137→  if (commits.length === 0) {
138→    return { signals: [], hasCommits: false };
139→  }
140→
141→  const signals = await Promise.all(commits.map(checkCiStatus));
142→  return { signals, hasCommits: true };
143→}
