570→        const now = new Date();
571→        await createObservation({
572→          surreal,
573→          workspaceRecord,
574→          text: patternText,
575→          severity: pattern.severity,
576→          sourceAgent: "observer_agent",
577→          observationType: "pattern",
578→          now,
579→          relatedRecords: relatedRecords.length > 0 ? relatedRecords : undefined,
580→        });
581→
582→        result.observations_created += 1;
583→      }
584→
585→      logInfo("observer.scan.synthesis", "Pattern synthesis completed", {
586→        patternsFound: patterns.length,
587→      });
588→    } else {
589→      logInfo("observer.llm.fallback", "Pattern synthesis failed, anomalies reported individually", {
590→        anomalyCount: anomalies.length,
591→      });
592→    }
593→  }
594→
595→  logInfo("observer.scan.completed", "Graph scan completed", {
596→    workspaceId: workspaceRecord.id,
597→    ...result,
598→  });
599→
600→  return result;
601→}
